def sigmoid(x):
    return 1 / (1 + np.exp(-x))

# Sigmoid activation function for the hidden layer
def hidden_layer_activation(x, w1, w2, b1, b2):
    a1 = w1 * x + b1
    z1 = a1.dot(w2) + b2
    if z1 <= 0:
        return 0
    else:
        a2 = sigmoid((z1 - 0.5) / (0.01 * np.sqrt(z1)))
        if a2 < 0 or a2 > 1:
            return a2
        else:  # a2 is between 0 and 1
            b1 = b1 - (a2 - b2) * x
            w2 = w2 - a2 * (x * x).dot(a2.T) * sigmoid_derivative(z2)
            z2 = a2.sum()
            if z2 <= b2:
                b2 = b2 - (z2 - z1) * z2
                w2 += z2 * x * x.T
            elif (z1 > 0).any():
                return b2 + (b2 - w2.mean()) * z1 / z1.mean()

